const limit = 12;

const rawProjects = $input.all().flatMap((item, itemIndex) => {
  const source = item.json;

  if (Array.isArray(source)) {
    return source.map((project) => ({ project, itemIndex }));
  }

  if (source && Array.isArray(source.data)) {
    return source.data.map((project) => ({ project, itemIndex }));
  }

  if (source && Array.isArray(source.projects)) {
    return source.projects.map((project) => ({ project, itemIndex }));
  }

  if (source && typeof source === 'object' && source.id) {
    return [{ project: source, itemIndex }];
  }

  return [];
});

const candidates = rawProjects
  .filter(({ project }) => {
    const stage = project.stage || '';
    if (stage === 'Done' || stage === 'Cancelled') {
      return false;
    }

    const openTaskCount = Number(project.open_task_count || 0);
    const blockersCount = Number(project.blockers_count || 0);
    const totalTaskCount = Number(project.total_task_count || 0);
    return openTaskCount > 0 || blockersCount > 0 || totalTaskCount > 0;
  })
  .sort((left, right) => {
    const blockerDiff = Number(right.project.blockers_count || 0) - Number(left.project.blockers_count || 0);
    if (blockerDiff !== 0) return blockerDiff;
    const openDiff = Number(right.project.open_task_count || 0) - Number(left.project.open_task_count || 0);
    if (openDiff !== 0) return openDiff;
    return String(left.project.name || '').localeCompare(String(right.project.name || ''));
  })
  .slice(0, limit);

return candidates.map(({ project, itemIndex }) => ({
  json: {
    project_id: project.id,
    project_name: project.name,
    stage: project.stage,
    rag: project.rag,
    status_summary: project.status_summary || '',
    blockers_count: Number(project.blockers_count || 0),
    open_task_count: Number(project.open_task_count || 0),
    completed_task_count: Number(project.completed_task_count || 0),
    total_task_count: Number(project.total_task_count || 0),
    completion_pct: Number(project.completion_pct || 0),
    implementation: project.implementation || null
  },
  pairedItem: { item: itemIndex }
}));

const candidateItems = $('Prepare Project Candidates').all();
const taskItems = $('Fetch Project Tasks').all();
const priorUpdateItems = $input.all();

const tasksByProjectId = new Map();
for (const item of taskItems) {
  const task = item.json;
  const projectId = typeof task.project_id === 'string' ? task.project_id : null;
  if (!projectId) continue;

  const current = tasksByProjectId.get(projectId) ?? [];
  current.push(task);
  tasksByProjectId.set(projectId, current);
}

const priorUpdatesByProjectId = new Map();
for (const item of priorUpdateItems) {
  const update = item.json;
  const projectId = typeof update.project_id === 'string' ? update.project_id : null;
  if (!projectId) continue;

  const current = priorUpdatesByProjectId.get(projectId) ?? [];
  current.push(update);
  priorUpdatesByProjectId.set(projectId, current);
}

return candidateItems.map((candidateItem, index) => {
  const project = candidateItem.json;

  const tasks = (tasksByProjectId.get(project.project_id) ?? []).slice(0, 25).map((task) => ({
    id: task.id,
    title: task.title,
    status: task.status,
    blocker: Boolean(task.blocker || task.dependency_blocked),
    due_at: task.due_at,
    updated_at: task.updated_at,
    waiting_on: task.waiting_on || null,
    needs_review: Boolean(task.needs_review),
    recent_update: task.recent_update || null,
    dependencies: Array.isArray(task.dependencies)
      ? task.dependencies
          .filter((dependency) => dependency.unresolved)
          .slice(0, 3)
          .map((dependency) => ({
            title: dependency.title,
            status: dependency.status,
          }))
      : [],
  }));

  const priorUpdates = (priorUpdatesByProjectId.get(project.project_id) ?? []).slice(0, 3);

  const context = {
    project,
    tasks,
    prior_updates: priorUpdates.map((update) => ({
      captured_for_date: update.captured_for_date,
      summary: update.summary,
      rag: update.rag,
      blockers: update.blockers,
      next_step: update.next_step,
      needs_decision: update.needs_decision,
    })),
  };

  const prompt = [
    'Review this Mission Control project and return ONLY valid JSON.',
    'Use exactly this schema:',
    '{',
    '  "summary": "1-2 sentences, 2000 chars max",',
    '  "rag": "Green|Yellow|Red",',
    '  "changes_today": ["short bullet", "..."],',
    '  "blockers": ["short blocker", "..."],',
    '  "next_step": "single next step or null",',
    '  "needs_decision": "single decision needed or null",',
    '  "related_task_ids": ["uuid", "..."]',
    '}',
    'Rules:',
    '- Be concise and concrete.',
    '- Prefer evidence from the provided tasks and prior updates only.',
    '- If there are no blockers, return an empty blockers array.',
    '- If no decision is needed, set needs_decision to null.',
    '- related_task_ids must be drawn only from tasks in the context.',
    '',
    'Context JSON:',
    JSON.stringify(context, null, 2),
  ].join('\n');

  return {
    json: {
      project_id: project.project_id,
      project_name: project.project_name,
      anthropic_request: {
        model: 'claude-sonnet-4-6',
        max_tokens: 1000,
        temperature: 0.2,
        system: 'You are a rigorous project analyst. Return strict JSON only with no markdown fences or commentary.',
        messages: [
          {
            role: 'user',
            content: prompt,
          },
        ],
      },
      prompt_context: context,
    },
    pairedItem: { item: index },
  };
});

function extractText(response) {
  if (!response || !Array.isArray(response.content)) return '';
  return response.content
    .filter((item) => item && item.type === 'text' && typeof item.text === 'string')
    .map((item) => item.text)
    .join('\n')
    .trim();
}

function parseJson(raw) {
  if (!raw) return null;

  const trimmed = raw.trim();
  const fenced = trimmed.match(/```(?:json)?\s*([\s\S]*?)```/i);
  const candidate = fenced ? fenced[1].trim() : trimmed;

  try {
    return JSON.parse(candidate);
  } catch {
    const start = candidate.indexOf('{');
    const end = candidate.lastIndexOf('}');
    if (start >= 0 && end > start) {
      try {
        return JSON.parse(candidate.slice(start, end + 1));
      } catch {
        return null;
      }
    }
    return null;
  }
}

function normalizeString(value, maxLength) {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  if (!trimmed) return null;
  return trimmed.slice(0, maxLength);
}

function normalizeArray(value, maxItems, maxLength) {
  if (!Array.isArray(value)) return [];
  return value
    .filter((item) => typeof item === 'string')
    .map((item) => item.trim())
    .filter(Boolean)
    .slice(0, maxItems)
    .map((item) => item.slice(0, maxLength));
}

function normalizeRag(value, fallback) {
  return value === 'Green' || value === 'Yellow' || value === 'Red' ? value : fallback;
}

const sourceItems = $('Build Haiku Request').all();
const responseItems = $input.all();

return responseItems.map((responseItem, index) => {
  const source = sourceItems[index].json;
  const response = responseItem.json;
  const responseText = extractText(response);
  const parsed = parseJson(responseText) || {};
  const project = source.prompt_context.project;
  const tasks = Array.isArray(source.prompt_context.tasks) ? source.prompt_context.tasks : [];
  const blockedTasks = tasks.filter((task) => task.blocker);

  const fallbackSummary = blockedTasks.length > 0
    ? `${project.project_name} is carrying ${tasks.length} tracked tasks with ${blockedTasks.length} active blocker${blockedTasks.length === 1 ? '' : 's'}, so progress is moving but constrained.`
    : `${project.project_name} is active in ${project.stage} with ${tasks.length} tracked tasks and ${project.completion_pct}% completion across the current task set.`;

  const fallbackRag = project.rag || (blockedTasks.length > 0 ? 'Yellow' : 'Green');

  const relatedTaskIds = normalizeArray(parsed.related_task_ids, 10, 120)
    .filter((taskId) => tasks.some((task) => task.id === taskId));

  const fallbackRelatedTaskIds = relatedTaskIds.length > 0
    ? relatedTaskIds
    : tasks.slice(0, Math.min(3, tasks.length)).map((task) => task.id);

  const blockers = normalizeArray(parsed.blockers, 8, 400);
  const fallbackBlockers = blockers.length > 0
    ? blockers
    : blockedTasks.slice(0, 5).map((task) => task.title);

  return {
    json: {
      project_id: source.project_id,
      summary: normalizeString(parsed.summary, 2000) || fallbackSummary,
      rag: normalizeRag(parsed.rag, fallbackRag),
      changes_today: normalizeArray(parsed.changes_today, 8, 400),
      blockers: fallbackBlockers,
      next_step: normalizeString(parsed.next_step, 1000),
      needs_decision: normalizeString(parsed.needs_decision, 1000),
      related_task_ids: fallbackRelatedTaskIds,
      source: 'n8n',
      model: source.anthropic_request.model,
      payload: {
        prompt_context: source.prompt_context,
        anthropic_response_text: responseText,
        anthropic_response_id: response.id || null,
      },
      sync_project_status_summary: true,
    },
    pairedItem: { item: index },
  };
});

function escapeHtml(value) {
  return String(value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/\"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function truncate(value, maxLength = 280) {
  const text = String(value || '').trim();
  if (!text) return '';
  if (text.length <= maxLength) return text;
  return `${text.slice(0, maxLength - 1).trimEnd()}…`;
}

function ragMeta(rag) {
  if (rag === 'Red') {
    return { label: 'Red', fg: '#8A1C14', bg: '#FCE8E6', border: '#D93025' };
  }
  if (rag === 'Yellow') {
    return { label: 'Yellow', fg: '#8A5A00', bg: '#FEF3C7', border: '#D97706' };
  }
  if (rag === 'Green') {
    return { label: 'Green', fg: '#166534', bg: '#DCFCE7', border: '#16A34A' };
  }
  return { label: 'Unknown', fg: '#4B5563', bg: '#E5E7EB', border: '#9CA3AF' };
}

function renderMetricCard(label, value, accent) {
  return `
    <td width="50%" style="padding:0 6px 12px 6px;vertical-align:top;">
      <div style="background:#fffdf8;border:1px solid #e7decf;border-top:4px solid ${accent};border-radius:16px;padding:16px 18px;">
        <div style="font-size:11px;line-height:1.4;letter-spacing:1.2px;text-transform:uppercase;color:#7b6f60;margin-bottom:10px;">${escapeHtml(label)}</div>
        <div style="font-size:30px;line-height:1;font-weight:700;color:#1f2937;">${escapeHtml(value)}</div>
      </div>
    </td>`;
}

function renderSectionHeader(eyebrow, title) {
  return `
    <div style="margin-bottom:16px;">
      <div style="font-size:11px;line-height:1.4;letter-spacing:1.2px;text-transform:uppercase;color:#7b6f60;margin-bottom:6px;">${escapeHtml(eyebrow)}</div>
      <div style="font-size:22px;line-height:1.2;font-weight:700;color:#111827;">${escapeHtml(title)}</div>
    </div>`;
}

function renderEmpty(text) {
  return `<div style="padding:14px 16px;border:1px dashed #d9cdb8;border-radius:14px;background:#fcf9f3;color:#6b6256;font-size:14px;line-height:1.6;">${escapeHtml(text)}</div>`;
}

function renderShippedList(tasks) {
  if (tasks.length === 0) {
    return renderEmpty('No shipped tasks recorded this week.');
  }

  return `
    <ul style="margin:0;padding:0;list-style:none;">
      ${tasks.slice(0, 5).map((task, index) => `
        <li style="${index === 0 ? '' : 'border-top:1px solid #efe6d8;'}padding:${index === 0 ? '0 0 12px 0' : '12px 0'};">
          <div style="font-size:15px;line-height:1.5;color:#1f2937;">
            <span style="display:inline-block;width:8px;height:8px;border-radius:999px;background:#1f7a4d;margin-right:10px;"></span>
            <span style="font-weight:600;">${escapeHtml(task.title || 'Untitled task')}</span>
          </div>
        </li>`).join('')}
    </ul>`;
}

function renderAttentionCards(projects) {
  if (projects.length === 0) {
    return renderEmpty('No projects currently need elevated attention.');
  }

  return projects.slice(0, 5).map((project) => {
    const meta = ragMeta(project.latest_rag);
    const trend = project.trend ? `Trend: ${project.trend}` : '';

    return `
      <div style="background:#ffffff;border:1px solid #e7decf;border-left:6px solid ${meta.border};border-radius:18px;padding:16px 18px;margin-top:12px;">
        <div style="margin-bottom:10px;">
          <span style="display:inline-block;padding:5px 10px;border-radius:999px;background:${meta.bg};color:${meta.fg};font-size:12px;font-weight:700;line-height:1;">${escapeHtml(meta.label)}</span>
          ${trend ? `<span style="margin-left:8px;font-size:12px;color:#6b6256;">${escapeHtml(trend)}</span>` : ''}
        </div>
        <div style="font-size:18px;line-height:1.35;font-weight:700;color:#111827;margin-bottom:8px;">${escapeHtml(project.project_name || 'Unnamed project')}</div>
        <div style="font-size:14px;line-height:1.65;color:#433b31;">${escapeHtml(truncate(project.latest_summary || 'No summary available.', 280))}</div>
      </div>`;
  }).join('');
}

function renderDecisionCards(projects) {
  if (projects.length === 0) {
    return renderEmpty('No project decisions are waiting right now.');
  }

  return projects.slice(0, 5).map((project) => {
    const meta = ragMeta(project.latest_rag);

    return `
      <div style="background:#fffdf8;border:1px solid #e7decf;border-left:6px solid ${meta.border};border-radius:16px;padding:16px 18px;margin-top:12px;">
        <div style="font-size:16px;line-height:1.35;font-weight:700;color:#111827;margin-bottom:8px;">${escapeHtml(project.project_name || 'Unnamed project')}</div>
        <div style="font-size:14px;line-height:1.65;color:#433b31;">${escapeHtml(truncate(project.latest_needs_decision || 'No decision recorded.', 320))}</div>
      </div>`;
  }).join('');
}

function renderSuggestionList(items) {
  if (items.length === 0) {
    return renderEmpty('No next-week suggestions were generated.');
  }

  return `
    <ol style="margin:0;padding:0 0 0 20px;">
      ${items.slice(0, 5).map((item) => `
        <li style="margin:0 0 12px 0;padding-left:6px;color:#433b31;font-size:14px;line-height:1.6;">${escapeHtml(item)}</li>`).join('')}
    </ol>`;
}

const shipped = Array.isArray($json.shipped) ? $json.shipped : [];
const projectRollups = Array.isArray($json.project_rollups) ? $json.project_rollups : [];
const attention = Array.isArray($json.projects_needing_attention) ? $json.projects_needing_attention : [];
const projectDecisions = Array.isArray($json.project_decisions) ? $json.project_decisions : [];
const suggestions = Array.isArray($json.next_week_suggestions) ? $json.next_week_suggestions : [];
const week = $json.week || {};
const subject = `Weekly Review • ${week.start_date || 'Unknown'} to ${week.end_date || 'Unknown'}`;

const text = [
  subject,
  '',
  `Shipped tasks: ${shipped.length}`,
  `Projects reviewed: ${projectRollups.length}`,
  `Projects needing attention: ${attention.length}`,
  `Project decisions: ${projectDecisions.length}`,
  '',
  'Top shipped:',
  ...(shipped.length > 0 ? shipped.slice(0, 5).map((task) => `- ${task.title}`) : ['- None']),
  '',
  'Projects needing attention:',
  ...(attention.length > 0
    ? attention.slice(0, 5).map((project) => `- ${project.project_name} [${project.latest_rag || 'Unknown'}]: ${truncate(project.latest_summary || 'No summary available.', 220)}`)
    : ['- None']),
  '',
  'Project decisions:',
  ...(projectDecisions.length > 0
    ? projectDecisions.slice(0, 5).map((project) => `- ${project.project_name}: ${truncate(project.latest_needs_decision || 'No decision recorded.', 220)}`)
    : ['- None']),
  '',
  'Next-week suggestions:',
  ...(suggestions.length > 0 ? suggestions.slice(0, 5).map((item) => `- ${item}`) : ['- None'])
].join('\n');

const html = `
  <div style="margin:0;padding:24px 0;background:#f3efe6;font-family:Georgia, 'Avenir Next', 'Segoe UI', Arial, sans-serif;">
    <div style="max-width:760px;margin:0 auto;padding:0 16px;">
      <div style="background:#1f3b35;border-radius:24px;padding:28px 30px;color:#f8f4eb;">
        <div style="font-size:11px;line-height:1.4;letter-spacing:1.4px;text-transform:uppercase;color:#c8d5d1;margin-bottom:10px;">Mission Control Weekly Review</div>
        <div style="font-size:30px;line-height:1.15;font-weight:700;margin-bottom:10px;">${escapeHtml(subject)}</div>
        <div style="font-size:14px;line-height:1.7;color:#d8e3df;max-width:560px;">A compact weekly readout of shipped work, projects that need attention, and decisions that should move next week.</div>
      </div>

      <table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="margin-top:18px;border-collapse:separate;border-spacing:0;">
        <tr>
          ${renderMetricCard('Shipped tasks', shipped.length, '#1f7a4d')}
          ${renderMetricCard('Projects reviewed', projectRollups.length, '#315c8a')}
        </tr>
        <tr>
          ${renderMetricCard('Need attention', attention.length, '#c76d1d')}
          ${renderMetricCard('Decisions needed', projectDecisions.length, '#b42318')}
        </tr>
      </table>

      <div style="background:#fffaf2;border:1px solid #e7decf;border-radius:22px;padding:22px 24px;margin-top:18px;">
        ${renderSectionHeader('Execution', 'Top shipped')}
        ${renderShippedList(shipped)}
      </div>

      <div style="background:#fffaf2;border:1px solid #e7decf;border-radius:22px;padding:22px 24px;margin-top:18px;">
        ${renderSectionHeader('Attention', 'Projects needing attention')}
        ${renderAttentionCards(attention)}
      </div>

      <div style="background:#fffaf2;border:1px solid #e7decf;border-radius:22px;padding:22px 24px;margin-top:18px;">
        ${renderSectionHeader('Decisions', 'Project decisions')}
        ${renderDecisionCards(projectDecisions)}
      </div>

      <div style="background:#fffaf2;border:1px solid #e7decf;border-radius:22px;padding:22px 24px;margin-top:18px;">
        ${renderSectionHeader('Focus', 'Next-week suggestions')}
        ${renderSuggestionList(suggestions)}
      </div>

      <div style="padding:16px 10px 0 10px;text-align:center;color:#7b6f60;font-size:12px;line-height:1.5;">
        Generated from weekly task activity and stored project status updates.
      </div>
    </div>
  </div>`;

return [{ json: { subject, text, html } }];

function getEtParts(date) {
  const formatter = new Intl.DateTimeFormat('en-US', {
    timeZone: 'America/New_York',
    weekday: 'short',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit'
  });
  const parts = Object.fromEntries(formatter.formatToParts(date).map((part) => [part.type, part.value]));
  return {
    weekday: parts.weekday,
    year: Number(parts.year),
    month: Number(parts.month),
    day: Number(parts.day),
    iso: `${parts.year}-${parts.month}-${parts.day}`
  };
}

function addDays(date, amount) {
  const next = new Date(date.getTime());
  next.setUTCDate(next.getUTCDate() + amount);
  return next;
}

const now = new Date();
const today = getEtParts(now);
let cursor = addDays(now, 1);
let nextBusiness = getEtParts(cursor);
while (nextBusiness.weekday === 'Sat' || nextBusiness.weekday === 'Sun') {
  cursor = addDays(cursor, 1);
  nextBusiness = getEtParts(cursor);
}

if (nextBusiness.month !== today.month || nextBusiness.year !== today.year) {
  return [{ json: { anchor_date: today.iso } }];
}

return [];

function escapeHtml(value) {
  return String(value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/\"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function truncate(value, maxLength = 260) {
  const text = String(value || '').trim();
  if (!text) return '';
  if (text.length <= maxLength) return text;
  return `${text.slice(0, maxLength - 1).trimEnd()}…`;
}

function unique(values) {
  return [...new Set(values.filter(Boolean))];
}

function ragMeta(rag) {
  if (rag === 'Red') {
    return { label: 'Red', fg: '#8A1C14', bg: '#FCE8E6', border: '#D93025' };
  }
  if (rag === 'Yellow') {
    return { label: 'Yellow', fg: '#8A5A00', bg: '#FEF3C7', border: '#D97706' };
  }
  if (rag === 'Green') {
    return { label: 'Green', fg: '#166534', bg: '#DCFCE7', border: '#16A34A' };
  }
  return { label: 'Unknown', fg: '#4B5563', bg: '#E5E7EB', border: '#9CA3AF' };
}

function ragSeverity(rag) {
  if (rag === 'Red') return 3;
  if (rag === 'Yellow') return 2;
  if (rag === 'Green') return 1;
  return 0;
}

function comparePriority(left, right) {
  return (
    ragSeverity(right.latest_rag) - ragSeverity(left.latest_rag) ||
    Number(right.blocker_days || 0) - Number(left.blocker_days || 0) ||
    Number(right.decision_days || 0) - Number(left.decision_days || 0) ||
    Number(right.updates_count || 0) - Number(left.updates_count || 0) ||
    String(left.project_name || '').localeCompare(String(right.project_name || ''))
  );
}

function renderMetricCard(label, value, accent) {
  return `
    <td width="50%" style="padding:0 6px 12px 6px;vertical-align:top;">
      <div style="background:#fffdf8;border:1px solid #e7decf;border-top:4px solid ${accent};border-radius:16px;padding:16px 18px;">
        <div style="font-size:11px;line-height:1.4;letter-spacing:1.2px;text-transform:uppercase;color:#7b6f60;margin-bottom:10px;">${escapeHtml(label)}</div>
        <div style="font-size:28px;line-height:1.05;font-weight:700;color:#1f2937;">${escapeHtml(value)}</div>
      </div>
    </td>`;
}

function renderSectionHeader(eyebrow, title) {
  return `
    <div style="margin-bottom:16px;">
      <div style="font-size:11px;line-height:1.4;letter-spacing:1.2px;text-transform:uppercase;color:#7b6f60;margin-bottom:6px;">${escapeHtml(eyebrow)}</div>
      <div style="font-size:22px;line-height:1.2;font-weight:700;color:#111827;">${escapeHtml(title)}</div>
    </div>`;
}

function renderEmpty(text) {
  return `<div style="padding:14px 16px;border:1px dashed #d9cdb8;border-radius:14px;background:#fcf9f3;color:#6b6256;font-size:14px;line-height:1.6;">${escapeHtml(text)}</div>`;
}

function renderWatchlistCards(projects) {
  if (projects.length === 0) {
    return renderEmpty('No material portfolio risks are standing out this month.');
  }

  return projects.slice(0, 5).map((project) => {
    const meta = ragMeta(project.latest_rag);
    const facts = [];
    if (project.trend) facts.push(`${project.trend} trend`);
    if (project.blocker_days) facts.push(`${project.blocker_days} blocker day${project.blocker_days === 1 ? '' : 's'}`);
    if (project.decision_days) facts.push(`${project.decision_days} decision day${project.decision_days === 1 ? '' : 's'}`);
    const blocker = Array.isArray(project.notable_blockers) ? project.notable_blockers[0] : null;

    return `
      <div style="background:#ffffff;border:1px solid #e7decf;border-left:6px solid ${meta.border};border-radius:18px;padding:16px 18px;margin-top:12px;">
        <div style="margin-bottom:10px;">
          <span style="display:inline-block;padding:5px 10px;border-radius:999px;background:${meta.bg};color:${meta.fg};font-size:12px;font-weight:700;line-height:1;">${escapeHtml(meta.label)}</span>
          ${facts.length > 0 ? `<span style="margin-left:8px;font-size:12px;color:#6b6256;">${escapeHtml(facts.join(' • '))}</span>` : ''}
        </div>
        <div style="font-size:18px;line-height:1.35;font-weight:700;color:#111827;margin-bottom:8px;">${escapeHtml(project.project_name || 'Unnamed project')}</div>
        <div style="font-size:14px;line-height:1.65;color:#433b31;">${escapeHtml(truncate(project.latest_summary || 'No summary available.', 280))}</div>
        ${blocker ? `<div style="margin-top:10px;font-size:13px;line-height:1.6;color:#5f5548;background:#faf4ea;border-radius:12px;padding:10px 12px;"><strong style="color:#332b22;">Top blocker:</strong> ${escapeHtml(truncate(blocker, 180))}</div>` : ''}
      </div>`;
  }).join('');
}

function renderDecisionCards(projects) {
  if (projects.length === 0) {
    return renderEmpty('No executive decisions are waiting right now.');
  }

  return projects.slice(0, 5).map((project) => {
    const meta = ragMeta(project.latest_rag);

    return `
      <div style="background:#fffdf8;border:1px solid #e7decf;border-left:6px solid ${meta.border};border-radius:16px;padding:16px 18px;margin-top:12px;">
        <div style="font-size:16px;line-height:1.35;font-weight:700;color:#111827;margin-bottom:8px;">${escapeHtml(project.project_name || 'Unnamed project')}</div>
        <div style="font-size:14px;line-height:1.65;color:#433b31;">${escapeHtml(truncate(project.latest_needs_decision || 'No decision recorded.', 320))}</div>
      </div>`;
  }).join('');
}

function renderMomentumCards(projects) {
  if (projects.length === 0) {
    return renderEmpty('No strong momentum themes stand out yet this month.');
  }

  return projects.slice(0, 4).map((project) => `
    <div style="background:#ffffff;border:1px solid #e7decf;border-left:6px solid #16A34A;border-radius:16px;padding:16px 18px;margin-top:12px;">
      <div style="font-size:16px;line-height:1.35;font-weight:700;color:#111827;margin-bottom:8px;">${escapeHtml(project.project_name || 'Unnamed project')}</div>
      <div style="font-size:14px;line-height:1.65;color:#433b31;">${escapeHtml(truncate(project.latest_summary || 'No summary available.', 220))}</div>
      ${project.latest_next_step ? `<div style="margin-top:10px;font-size:13px;line-height:1.6;color:#24543e;background:#edf8f1;border-radius:12px;padding:10px 12px;"><strong style="color:#17422f;">Next:</strong> ${escapeHtml(truncate(project.latest_next_step, 180))}</div>` : ''}
    </div>`).join('');
}

function renderFocusList(items) {
  if (items.length === 0) {
    return renderEmpty('No month-close focus items were generated.');
  }

  return `
    <ol style="margin:0;padding:0 0 0 20px;">
      ${items.slice(0, 5).map((item) => `
        <li style="margin:0 0 12px 0;padding-left:6px;color:#433b31;font-size:14px;line-height:1.6;">${escapeHtml(item)}</li>`).join('')}
    </ol>`;
}

const month = $json.month || {};
const totals = $json.totals || {};
const rollups = Array.isArray($json.project_rollups) ? $json.project_rollups : [];
const subject = `Monthly Review • ${month.start_date || 'Unknown'} to ${month.end_date || 'Unknown'}`;

const redProjects = rollups.filter((project) => project.latest_rag === 'Red');
const yellowProjects = rollups.filter((project) => project.latest_rag === 'Yellow');
const greenProjects = rollups.filter((project) => project.latest_rag === 'Green');

const attention = rollups
  .filter((project) => project.latest_rag === 'Red' || project.latest_rag === 'Yellow' || Number(project.blocker_days || 0) > 0 || Boolean(project.latest_needs_decision))
  .sort(comparePriority);

const decisions = rollups
  .filter((project) => Boolean(project.latest_needs_decision))
  .sort(comparePriority);

const momentum = rollups
  .filter((project) => project.latest_rag === 'Green' && project.project_stage && !['Proposed', 'Planned'].includes(project.project_stage) && !project.latest_needs_decision)
  .sort((left, right) => Number(right.updates_count || 0) - Number(left.updates_count || 0) || String(left.project_name || '').localeCompare(String(right.project_name || '')));

const blockerProjects = rollups
  .filter((project) => Number(project.blocker_days || 0) > 0 || (Array.isArray(project.notable_blockers) && project.notable_blockers.length > 0))
  .sort(comparePriority);

const focusItems = unique([
  ...attention.slice(0, 3).map((project) => project.latest_next_step ? `${project.project_name}: ${project.latest_next_step}` : `Define the next concrete move for ${project.project_name}.`),
  ...decisions.slice(0, 2).map((project) => `${project.project_name}: resolve decision — ${project.latest_needs_decision}`),
  ...momentum.slice(0, 2).map((project) => project.latest_next_step ? `Protect momentum on ${project.project_name}: ${project.latest_next_step}` : `Protect momentum on ${project.project_name}.`),
]).slice(0, 5);

const executiveSummary = redProjects.length > 0
  ? `${redProjects.length} red project and ${yellowProjects.length} yellow project${yellowProjects.length === 1 ? '' : 's'} are driving portfolio risk this month across ${rollups.length} active projects. ${decisions.length} decision${decisions.length === 1 ? '' : 's'} and ${blockerProjects.length} blocker-shaped effort${blockerProjects.length === 1 ? '' : 's'} need movement before month close.`
  : yellowProjects.length > 0
    ? `The portfolio is broadly stable, with ${yellowProjects.length} yellow project${yellowProjects.length === 1 ? '' : 's'} to manage and ${decisions.length} open decision${decisions.length === 1 ? '' : 's'} across ${rollups.length} active projects this month.`
    : `The portfolio is stable across ${rollups.length} active projects, with no red risks and ${totals.shipped_count || 0} shipped task${Number(totals.shipped_count || 0) === 1 ? '' : 's'} captured in stored weekly snapshots this month.`;

const text = [
  subject,
  '',
  executiveSummary,
  '',
  `Weekly snapshots: ${totals.weekly_snapshot_count || 0}`,
  `Project status updates: ${totals.project_status_update_count || 0}`,
  `Projects with updates: ${totals.projects_with_updates || 0}`,
  `Risk mix (R/Y/G): ${redProjects.length}/${yellowProjects.length}/${greenProjects.length}`,
  `Decisions waiting: ${decisions.length}`,
  '',
  'Watchlist:',
  ...(attention.length > 0
    ? attention.slice(0, 5).map((project) => `- ${project.project_name} [${project.latest_rag || 'Unknown'}]: ${truncate(project.latest_summary || 'No summary available.', 220)}`)
    : ['- None']),
  '',
  'Decisions to resolve:',
  ...(decisions.length > 0
    ? decisions.slice(0, 5).map((project) => `- ${project.project_name}: ${truncate(project.latest_needs_decision || 'No decision recorded.', 220)}`)
    : ['- None']),
  '',
  'Month-close focus:',
  ...(focusItems.length > 0 ? focusItems.map((item) => `- ${item}`) : ['- None'])
].join('\n');

const html = `
  <div style="margin:0;padding:24px 0;background:#f3efe6;font-family:Georgia, 'Avenir Next', 'Segoe UI', Arial, sans-serif;">
    <div style="max-width:760px;margin:0 auto;padding:0 16px;">
      <div style="background:#1f3b35;border-radius:24px;padding:28px 30px;color:#f8f4eb;">
        <div style="font-size:11px;line-height:1.4;letter-spacing:1.4px;text-transform:uppercase;color:#c8d5d1;margin-bottom:10px;">Mission Control Monthly Review</div>
        <div style="font-size:30px;line-height:1.15;font-weight:700;margin-bottom:10px;">${escapeHtml(subject)}</div>
        <div style="font-size:15px;line-height:1.75;color:#d8e3df;max-width:620px;">${escapeHtml(executiveSummary)}</div>
        <div style="margin-top:14px;font-size:12px;line-height:1.6;color:#b9cbc6;">${escapeHtml(`${totals.weekly_snapshot_count || 0} weekly snapshots • ${totals.project_status_update_count || 0} project updates captured • ${totals.projects_with_updates || 0} active projects in review window`)}</div>
      </div>

      <table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="margin-top:18px;border-collapse:separate;border-spacing:0;">
        <tr>
          ${renderMetricCard('Active projects', rollups.length, '#315c8a')}
          ${renderMetricCard('Shipped tasks', totals.shipped_count || 0, '#1f7a4d')}
        </tr>
        <tr>
          ${renderMetricCard('Risk mix R / Y / G', `${redProjects.length} / ${yellowProjects.length} / ${greenProjects.length}`, '#c76d1d')}
          ${renderMetricCard('Decisions waiting', decisions.length, '#b42318')}
        </tr>
      </table>

      <div style="background:#fffaf2;border:1px solid #e7decf;border-radius:22px;padding:22px 24px;margin-top:18px;">
        ${renderSectionHeader('Watchlist', 'Projects needing executive attention')}
        ${renderWatchlistCards(attention)}
      </div>

      <div style="background:#fffaf2;border:1px solid #e7decf;border-radius:22px;padding:22px 24px;margin-top:18px;">
        ${renderSectionHeader('Decisions', 'Items to resolve before month close')}
        ${renderDecisionCards(decisions)}
      </div>

      <div style="background:#fffaf2;border:1px solid #e7decf;border-radius:22px;padding:22px 24px;margin-top:18px;">
        ${renderSectionHeader('Momentum', 'Workstreams worth protecting')}
        ${renderMomentumCards(momentum)}
      </div>

      <div style="background:#fffaf2;border:1px solid #e7decf;border-radius:22px;padding:22px 24px;margin-top:18px;">
        ${renderSectionHeader('Month Close', 'Recommended focus')}
        ${renderFocusList(focusItems)}
      </div>

      <div style="padding:16px 10px 0 10px;text-align:center;color:#7b6f60;font-size:12px;line-height:1.5;">
        Generated from stored weekly snapshots and project status updates.
      </div>
    </div>
  </div>`;

return [{ json: { subject, text, html } }];
